```typescript
export function StreamingText({
  content,
  isStreaming = false,
  textEffect = DEFAULT_TEXT_EFFECT,
}: StreamingTextProps) {
  const animatedConfig = resolveStreamdownAnimation(textEffect);

  return (
    <div className={cn('relative', isStreaming && 'streaming-cursor')}>
      <Streamdown
        shikiTheme={['github-light', 'github-dark']}
        linkSafety={linkSafety}
        animated={animatedConfig}
        isAnimating={isStreaming}
      >
        {content}
      </Streamdown>
    </div>
  );
}
```

Key changes:
- Add `textEffect` prop with default `DEFAULT_TEXT_EFFECT`
- Call `resolveStreamdownAnimation(textEffect)` to convert to streamdown's format
- Pass `animated={animatedConfig}` to Streamdown (either `false` or an `AnimateOptions` object)
- Pass `isAnimating={isStreaming}` to Streamdown (controls whether animation spans are generated; when `false`, completed messages have zero animation DOM overhead)
- Import `streamdown/styles.css` for the animation keyframes

The existing `linkSafety`, `LinkSafetyModal`, and `createPortal` code remain unchanged.

